// ===================================
// PURE JS CRYPTO FALLBACK (No 'require')
// ===================================
const PURE_CRYPTO = {
  sha256: function(ascii) {
    function rightRotate(value, amount) { return (value>>>amount) | (value<<(32 - amount)); };
    var mathPow = Math.pow;
    var maxWord = mathPow(2, 32);
    var lengthProperty = 'length';
    var i, j;
    var result = '';
    var words = [];
    var asciiBitLength = ascii[lengthProperty]*8;
    var hash = PURE_CRYPTO.sha256.h = PURE_CRYPTO.sha256.h || [];
    var k = PURE_CRYPTO.sha256.k = PURE_CRYPTO.sha256.k || [];
    var primeCounter = k[lengthProperty];
    var isComposite = {};
    for (var candidate = 2; primeCounter < 64; candidate++) {
      if (!isComposite[candidate]) {
        for (i = 0; i < 313; i += candidate) { isComposite[i] = candidate; }
        hash[primeCounter] = (mathPow(candidate, .5)*maxWord)|0;
        k[primeCounter++] = (mathPow(candidate, 1/3)*maxWord)|0;
      }
    }
    ascii += '\x80';
    while (ascii[lengthProperty]%64 - 56) ascii += '\x00';
    for (i = 0; i < ascii[lengthProperty]; i++) {
      j = ascii.charCodeAt(i);
      if (j>>8) return; 
      words[i>>2] |= j << ((3 - i)%4)*8;
    }
    words[words[lengthProperty]] = ((asciiBitLength/maxWord)|0);
    words[words[lengthProperty]] = (asciiBitLength)
    for (j = 0; j < words[lengthProperty];) {
      var w = words.slice(j, j += 16);
      var oldHash = hash;
      hash = hash.slice(0, 8);
      for (i = 0; i < 64; i++) {
        var i2 = i + j;
        var w15 = w[i - 15], w2 = w[i - 2];
        var a = hash[0], e = hash[4];
        var temp1 = hash[7]
          + (rightRotate(e, 6) ^ rightRotate(e, 11) ^ rightRotate(e, 25)) 
          + ((e&hash[5])^((~e)&hash[6]))
          + k[i]
          + (w[i] = (i < 16) ? w[i] : (
              w[i - 16]
              + (rightRotate(w15, 7) ^ rightRotate(w15, 18) ^ (w15>>>3)) 
              + w[i - 7]
              + (rightRotate(w2, 17) ^ rightRotate(w2, 19) ^ (w2>>>10))
            )|0
          );
        var temp2 = (rightRotate(a, 2) ^ rightRotate(a, 13) ^ rightRotate(a, 22)) 
          + ((a&hash[1])^(a&hash[2])^(hash[1]&hash[2]));
        hash = [(temp1 + temp2)|0].concat(hash);
        hash[4] = (hash[4] + temp1)|0;
      }
      for (i = 0; i < 8; i++) { hash[i] = (hash[i] + oldHash[i])|0; }
    }
    for (i = 0; i < 8; i++) {
      for (j = 3; j + 1; j--) {
        var b = (hash[i]>>(j*8))&255;
        result += ((b < 16) ? 0 : '') + b.toString(16);
      }
    }
    return result;
  },

  hmacSha256: function(key, message) {
    if (typeof key === 'string') {
        key = unescape(encodeURIComponent(key));
    }
    if (typeof message === 'string') {
        message = unescape(encodeURIComponent(message));
    }
    var blockSize = 64;
    var keyBytes = [];
    for (var i = 0; i < key.length; i++) {
        keyBytes.push(key.charCodeAt(i));
    }
    if (keyBytes.length > blockSize) {
        var keyHashHex = PURE_CRYPTO.sha256(key);
        keyBytes = [];
        for (var i = 0; i < keyHashHex.length; i += 2) {
            keyBytes.push(parseInt(keyHashHex.substr(i, 2), 16));
        }
    }
    while (keyBytes.length < blockSize) {
        keyBytes.push(0);
    }
    var oKeyPad = [], iKeyPad = [];
    for (var i = 0; i < blockSize; i++) {
        oKeyPad.push(keyBytes[i] ^ 0x5c);
        iKeyPad.push(keyBytes[i] ^ 0x36);
    }
    var iKeyPadStr = String.fromCharCode.apply(null, iKeyPad);
    var oKeyPadStr = String.fromCharCode.apply(null, oKeyPad);
    var innerHashHex = PURE_CRYPTO.sha256(iKeyPadStr + message);
    var innerHashStr = '';
    for (var i = 0; i < innerHashHex.length; i += 2) {
        innerHashStr += String.fromCharCode(parseInt(innerHashHex.substr(i, 2), 16));
    }
    var outerHashHex = PURE_CRYPTO.sha256(oKeyPadStr + innerHashStr);
    return Buffer.from(outerHashHex, 'hex').toString('base64url');
  },

  hashPassword: function(pwd, salt) {
      let h = PURE_CRYPTO.sha256(salt + pwd);
      for (let i = 0; i < 1000; i++) {
          h = PURE_CRYPTO.sha256(h + salt + i);
      }
      return h;
  },

  randomStr: function(len) {
      const crypto = require('crypto');
      return crypto.randomBytes(len).toString('hex').slice(0, len);
  }
};
