if (!googleToken.aud || googleToken.aud !== EXPECTED_AUD) {
  throw new Error('SSO_INVALID: Token nao pertence a esta aplicacao (aud ausente ou incorreto)');
}
if (googleToken.email_verified === false || googleToken.email_verified === 'false') {
