// SEC: S1 - Validar IP contra regex estrita
if (rawIp.includes(',')) rawIp = rawIp.split(',')[0].trim();
const IPV4 = /^(\d{1,3}\.){3}\d{1,3}$/;
const IPV6 = /^([0-9a-fA-F]{0,4}:){2,7}[0-9a-fA-F]{0,4}$/;
const ip = (IPV4.test(rawIp) || IPV6.test(rawIp)) ? rawIp : 'unknown';
const now = Date.now();
const WINDOW = 30 * 60 * 1000;
const MAX_ATTEMPTS = 3;

const { email, password } = $input.first().json.body;
// SEC: A5 - Chavear por email ALEM de IP
const store = globalThis._loginRateLimit = globalThis._loginRateLimit || {};
const ipKey = 'ip:' + ip;
const emailKey = email ? 'email:' + email.toLowerCase().trim() : null;

function checkLimit(key) {
  if (!key) return;
  if (!store[key] || (now - store[key].firstAttempt) > WINDOW) {
    store[key] = { count: 0, firstAttempt: now };
  }
  store[key].count++;
  if (store[key].count > MAX_ATTEMPTS) {
    throw new Error('RATE_LIMIT: Muitas tentativas de login. Aguarde 30 minutos');
  }
}
checkLimit(ipKey);
checkLimit(emailKey);

const entry = store[ipKey];
return [{ json: { email, passwordInput: password, ip, _pendingRateEntry: {
  ip_address: ip,
  attempted_at: new Date(now).toISOString(),
  lockout_until: entry && entry.lockedUntil ? new Date(entry.lockedUntil).toISOString() : null,
  attempt_count: entry ? entry.count : 1
} } }];

