function signJWT(claims, secret) {
  if (!secret) throw new Error('CONFIGURACAO: N8N_JWT_SECRET nao definida');
  const header = Buffer.from(JSON.stringify({ alg: 'HS256', typ: 'JWT' })).toString('base64url');
