const item = $input.first().json;
const assignments = item.body.assignments || [];
const user = (item._auth?.email || item.authenticatedUser?.email || 'sistema').replace(/'/g, '');
if (!assignments.length) throw new Error('MISSING_FIELDS: assignments array is empty');
const safe = assignments.slice(0, 5000).map(a => ({
  n_pi: String(a.n_pi || '').replace(/'/g, ''),
  responsavel: String(a.responsavel || '').replace(/'/g, ''),
  mes: String(a.mes_referencia || '').replace(/'/g, ''),
  conta: String(a.conta || '').replace(/'/g, '')
})).filter(a => a.n_pi && a.responsavel && a.mes);
if (!safe.length) throw new Error('MISSING_FIELDS: no valid assignments after sanitization');
// F5-a: dedup por n_pi+mes — BigQuery MERGE aborta se a fonte tiver a mesma chave 2x
const dedup = new Map();
for (const a of safe) dedup.set(a.n_pi + '|' + a.mes, a);
const finalRows = [...dedup.values()];
if (!finalRows.length) throw new Error('MISSING_FIELDS: no valid assignments after dedup');
const q = String.fromCharCode(39);
const structs = finalRows.map(a => 'STRUCT(' + q+a.n_pi+q + ' AS n_pi, ' + q+a.responsavel+q + ' AS responsavel, ' + q+a.mes+q + ' AS mes_referencia, ' + q+a.conta+q + ' AS conta)').join(',');
const sql = 'MERGE `checking-grupoom.form_checking.pi_responsaveis` T USING (SELECT * FROM UNNEST(ARRAY<STRUCT<n_pi STRING, responsavel STRING, mes_referencia STRING, conta STRING>>[' + structs + ']) ) S ON T.n_pi = S.n_pi AND T.mes_referencia = S.mes_referencia WHEN MATCHED THEN UPDATE SET responsavel = S.responsavel, responsavel_nome = S.responsavel, conta = S.conta, atribuido_por = ' + q+user+q + ', atribuido_em = CURRENT_TIMESTAMP() WHEN NOT MATCHED THEN INSERT (n_pi, responsavel, responsavel_nome, mes_referencia, conta, atribuido_por, atribuido_em) VALUES (S.n_pi, S.responsavel, S.responsavel, S.mes_referencia, S.conta, ' + q+user+q + ', CURRENT_TIMESTAMP())';
return [{ json: { sql, count: finalRows.length } }];

